import{_ as e,o as d,c as l,a3 as a}from"./chunks/framework.d0TBG0Rg.js";const f=JSON.parse('{"title":"PJSK 专项功能","description":"PJSK 查分、查榜、组卡、猜歌等功能的用法说明。","frontmatter":{"title":"PJSK 专项功能","description":"PJSK 查分、查榜、组卡、猜歌等功能的用法说明。"},"headers":[],"relativePath":"features/pjsk.md","filePath":"features/pjsk.md"}'),o={name:"features/pjsk.md"};function s(c,t,i,r,n,y){return d(),l("div",null,[...t[0]||(t[0]=[a('<h1 id="🎵-pjsk-模块功能" tabindex="-1">🎵 PJSK 模块功能 <a class="header-anchor" href="#🎵-pjsk-模块功能" aria-label="Permalink to &quot;🎵 PJSK 模块功能&quot;">​</a></h1><div class="warning custom-block"><p class="custom-block-title">⚠️ 账号防丢指南</p><p><strong>在进行账号上传或绑定操作前，请务必保存你的引继码与密码！</strong> 以免因意外情况、网络波动或平台风控导致游戏账号丢失。Bot 无法为您找回丢失的账号。</p></div><p style="font-size:14px;opacity:0.8;margin-bottom:25px;line-height:1.8;"><strong>🌐 多服务器前缀支持：</strong><br> 在大部分查分、查榜、绑定指令前添加特定前缀，即可跨服查询：<br><code>cn</code> (国服) | <code>tw</code> (台服) | <code>en</code> (国际服) | <code>kr</code> (韩服) | 不加前缀默认日服<br><em>（示例：<code>cn绑定</code>、<code>twsk</code>、<code>en逮捕</code>）</em></p> --- <div class="mzk-card mzk-card--cyan"><h3>🔗 账号绑定与数据上传</h3><p>通过游戏 UID 进行绑定。绑定后默认为「不给看」模式，无法被其他人 @ 查询。</p><div class="mzk-table-wrapper"><table tabindex="0"><thead><tr><th style="text-align:left;">指令</th><th style="text-align:left;">说明</th></tr></thead><tbody><tr><td style="text-align:left;"><code>[前缀]绑定 [ID]</code></td><td style="text-align:left;">绑定指定服务器的 PJSK 游戏 ID</td></tr><tr><td style="text-align:left;"><code>给看</code> / <code>不给看</code></td><td style="text-align:left;">开放或关闭他人逮捕/查询自己的权限</td></tr></tbody></table></div><h4>📥 高级数据上传 (查榜/MySekai必备)</h4><p>部分进阶功能需上传数据至数据库才可使用。</p><div class="mzk-table-wrapper"><table tabindex="0"><thead><tr><th style="text-align:left;">数据类型</th><th style="text-align:left;">上传说明</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>基础数据 (日/台等)</strong></td><td style="text-align:left;">访问 <a href="http://go.mikuware.top" target="_blank" style="color:#39C5BB;font-weight:bold;">👉 数据上传页面</a> 获取 Suite。（日服玩家可直接私聊 Bot 发送引继码，需重新引继）</td></tr><tr><td style="text-align:left;"><strong>MySekai 数据</strong></td><td style="text-align:left;">访问 <a href="https://haruki.seiunx.com/upload-data" target="_blank" style="color:#39C5BB;font-weight:bold;">👉 MySekai 数据上传页</a>。Android 推荐「Haruki工具箱」；iOS 推荐 MitM 代理模块。</td></tr></tbody></table></div></div><div class="mzk-card mzk-card--purple"><h3>📝 玩家信息、查分与 MySekai</h3><div class="mzk-table-wrapper"><table tabindex="0"><thead><tr><th style="text-align:left;">指令</th><th style="text-align:left;">说明</th></tr></thead><tbody><tr><td style="text-align:left;"><code>个人信息</code></td><td style="text-align:left;">生成日服/默认账号的个人信息卡片图</td></tr><tr><td style="text-align:left;"><code>[前缀]个人信息</code></td><td style="text-align:left;">生成指定外服的个人信息卡片（如：<code>cn个人信息</code> 或 <code>cnpjskprofile</code>）</td></tr><tr><td style="text-align:left;"><code>[前缀]逮捕 [@/ID]</code></td><td style="text-align:left;">查询目标 Ex/Ma/Apd 难度的 FC、AP 进度</td></tr><tr><td style="text-align:left;"><code>rk</code></td><td style="text-align:left;">获取玩家排位信息</td></tr><tr><td style="text-align:left;"><code>b39</code></td><td style="text-align:left;">获取 Rating 最高的 39 首歌与总分 (需上传数据，仅供参考)</td></tr><tr><td style="text-align:left;"><code>pjsk b30</code></td><td style="text-align:left;">获取 Rating 最高的 30 首歌与平均分 (需上传数据，算法不同)</td></tr><tr><td style="text-align:left;"><code>ms分析</code> / <code>msa2</code></td><td style="text-align:left;">(MySekai) 分析现存材料情况 (msa2 为新版 UI)</td></tr><tr><td style="text-align:left;"><code>ms地图 [1-4]</code></td><td style="text-align:left;">(MySekai) 生成资源分布图 (1草原/2花田/3沙滩/4废墟)</td></tr><tr><td style="text-align:left;"><code>ms照片 [序号]</code></td><td style="text-align:left;">(MySekai) 下载用户在游戏内拍摄的照片</td></tr></tbody></table></div></div><div class="mzk-card mzk-card--blue"><h3>📈 高阶查榜与 PT 追踪</h3><p><strong>WL 活动特供：</strong> 在查榜指令前加 <code>wl</code>，并在末尾加 <code>-c [角色]</code> 可查单榜 (如：<code>wlsk 100 -c haruka</code>)。</p><div class="mzk-table-wrapper"><table tabindex="0"><thead><tr><th style="text-align:left;">指令</th><th style="text-align:left;">说明</th><th style="text-align:left;">示例</th></tr></thead><tbody><tr><td style="text-align:left;"><code>sk [排名/ID]</code></td><td style="text-align:left;">查指定排名/玩家分数 (支持同时查最多7人)</td><td style="text-align:left;"><code>sk 100</code></td></tr><tr><td style="text-align:left;"><code>sk预测*</code></td><td style="text-align:left;">获取预测线信息 (仅日服单榜，不一定能获取到所有档线，数据源于33)</td><td style="text-align:left;"><code>sk预测</code></td></tr><tr><td style="text-align:left;"><code>查房 [排名]</code></td><td style="text-align:left;">查询特定排名最近 1 小时的活动情况</td><td style="text-align:left;"><code>查房 50</code></td></tr><tr><td style="text-align:left;"><code>分数线 [排名]</code></td><td style="text-align:left;">查看本期活动中特定排名的分数趋势</td><td style="text-align:left;"><code>分数线 1000</code></td></tr><tr><td style="text-align:left;"><code>时速 [分钟]</code></td><td style="text-align:left;">查各榜线特定时间内 PT 增长时速 (最大1440)</td><td style="text-align:left;"><code>时速 10</code></td></tr><tr><td style="text-align:left;"><code>半日速</code> / <code>日速</code></td><td style="text-align:left;">查看近半天 / 近一天各榜线的 PT 增长速度</td><td style="text-align:left;"><code>日速</code></td></tr><tr><td style="text-align:left;"><code>追踪 [排1] [排2]</code></td><td style="text-align:left;">追踪目前特定排名在本期的 PT 与排名趋势</td><td style="text-align:left;"><code>追踪 1 2</code></td></tr></tbody></table></div></div><div class="mzk-card mzk-card--yellow"><h3>🎫 组卡与查卡推荐 (需上传数据)</h3><div class="mzk-table-wrapper"><table tabindex="0"><thead><tr><th style="text-align:left;">指令</th><th style="text-align:left;">说明</th><th style="text-align:left;">示例</th></tr></thead><tbody><tr><td style="text-align:left;"><code>组卡 [队名] [属性]</code></td><td style="text-align:left;">指定箱活中推荐最佳卡组 top7 (默认嫉妒ex)。队名含(ln/mmj/vbs/ws/25/vs)，属性含(绿/粉/橙/蓝/紫)。</td><td style="text-align:left;"><code>组卡 ln 橙</code></td></tr><tr><td style="text-align:left;"><code>活动组卡 [歌名] [难度]</code></td><td style="text-align:left;">当前活动推荐最佳卡组 top7。不填默认嫉妒ex。WL活第一参数识别为角色。</td><td style="text-align:left;"><code>活动组卡 龙 hard</code></td></tr><tr><td style="text-align:left;"><code>挑战组卡 [角色] [歌名] [难度]</code></td><td style="text-align:left;">每日挑战推荐最佳卡组 top7。</td><td style="text-align:left;"><code>挑战组卡 ick 10th master</code></td></tr><tr><td style="text-align:left;"><code>最强组卡</code></td><td style="text-align:left;">返回您同色同队中分数最高的卡组 top7 (默认嫉妒ex)。不需要参数。</td><td style="text-align:left;"><code>最强组卡</code></td></tr></tbody></table></div></div><div class="mzk-card mzk-card--red"><h3>🎶 歌曲谱面与别名设置</h3><div class="mzk-alert">⚠️ 别名设置日志按日公示，违规乱设别名将被删词或封禁 Bot 使用权！</div><div class="mzk-table-wrapper"><table tabindex="0"><thead><tr><th style="text-align:left;">指令</th><th style="text-align:left;">说明</th></tr></thead><tbody><tr><td style="text-align:left;"><code>pinfo [曲名]*</code></td><td style="text-align:left;">查询歌曲信息</td></tr><tr><td style="text-align:left;"><code>pjskbpm [曲名]*</code></td><td style="text-align:left;">查看当前歌曲的 BPM</td></tr><tr><td style="text-align:left;"><code>查bpm [数字]*</code></td><td style="text-align:left;">查询对应 BPM 的所有歌曲</td></tr><tr><td style="text-align:left;"><code>查物量 [数字]*</code></td><td style="text-align:left;">查询所有歌曲难度中，谱面物量等于指定物量的歌曲及难度</td></tr><tr><td style="text-align:left;"><code>[歌名]谱面预览*</code></td><td style="text-align:left;">默认 master 难度。可加 <code>ex</code> 或 <code>apd</code> 前缀查看其他难度。</td></tr><tr><td style="text-align:left;"><code>[歌名]技能预览*</code></td><td style="text-align:left;">默认 master 难度。返回谱面技能分布及分数占比。</td></tr><tr><td style="text-align:left;"><code>难度排行*</code></td><td style="text-align:left;">格式：<code>难度排行 level [难度]</code>。可加 <code>fc/ap</code> 前缀。目前仅支持紫谱及早期红谱。</td></tr><tr><td style="text-align:left;"><code>musicset [新] to [旧]</code></td><td style="text-align:left;">设置歌曲全局昵称 (删除用 <code>musicdel [昵称]</code>)</td></tr><tr><td style="text-align:left;"><code>charaset [新] to [旧]</code></td><td style="text-align:left;">设置角色全局昵称 (如: <code>charaset knd to 宵崎奏</code>)</td></tr><tr><td style="text-align:left;"><code>grcharaset [新] to [旧]</code></td><td style="text-align:left;">设置<strong>仅当前群可用</strong>的角色昵称</td></tr><tr><td style="text-align:left;"><code>charalias [昵称]*</code></td><td style="text-align:left;">查看特定角色的所有已绑定昵称</td></tr></tbody></table></div></div><div class="mzk-card mzk-card--pink"><h3>🎫 卡牌与活动全能图鉴</h3><div class="mzk-table-wrapper"><table tabindex="0"><thead><tr><th style="text-align:left;">指令</th><th style="text-align:left;">说明</th></tr></thead><tbody><tr><td style="text-align:left;"><code>查卡 [角色/卡面ID]*</code></td><td style="text-align:left;">查角色所有卡牌，或查特定 ID 卡牌的详细信息</td></tr><tr><td style="text-align:left;"><code>card [编号]*</code></td><td style="text-align:left;">返回指定卡面图片</td></tr><tr><td style="text-align:left;"><code>cardinfo [编号]*</code></td><td style="text-align:left;">返回卡面基础信息（属性、技能、当期活动等）</td></tr><tr><td style="text-align:left;"><code>活动总览*</code></td><td style="text-align:left;">返回当前所有活动的概要 (因图片较大，部分频道不可用)</td></tr><tr><td style="text-align:left;"><code>查活动 [ID/关键字]*</code></td><td style="text-align:left;">查指定活动。支持单/多关键字精细筛选 (如 <code>查活动 草 5v5</code>、<code>查活动 knd 蓝</code>)</td></tr></tbody></table></div></div><div class="mzk-card mzk-card--green"><h3>🎮 互动小游戏与 5v5 活动功能</h3><div class="mzk-table-wrapper"><table tabindex="0"><thead><tr><th style="text-align:left;">指令</th><th style="text-align:left;">说明</th></tr></thead><tbody><tr><td style="text-align:left;"><code>5v5胜率 / 分数</code></td><td style="text-align:left;">(5v5活动限定) 返回双方胜率/分数。</td></tr><tr><td style="text-align:left;"><code>tf启动</code></td><td style="text-align:left;">(5v5活动限定) 送3次无偿火给绑定 ID 的用户。</td></tr><tr><td style="text-align:left;"><code>pjsk听歌识曲*</code></td><td style="text-align:left;">发送片段猜歌名/花名 (40s限时)。输入 <code>结束猜曲</code> 中断。</td></tr><tr><td style="text-align:left;"><code>pjsk猜卡面*</code></td><td style="text-align:left;">发送卡面局部截图猜角色 (40s限时)。输入 <code>结束猜卡面</code> 中断。</td></tr><tr><td style="text-align:left;"><code>pjsk抽卡*</code></td><td style="text-align:left;">格式：<code>pjsk抽卡/pjskXX连/pjsk反抽卡 [当期卡池编号]</code>。模拟抽卡体验。</td></tr><tr><td style="text-align:left;"><code>看 [角色]*</code></td><td style="text-align:left;">返回该角色随机卡图。</td></tr><tr><td style="text-align:left;"><code>随个 [组合] [level]*</code></td><td style="text-align:left;">返回随机指定等级歌曲 info。如果有组合名，会从该组合中随机。</td></tr><tr><td style="text-align:left;"><code>葱什么*</code></td><td style="text-align:left;">返回随机歌曲 info。</td></tr></tbody></table></div></div>',11)])])}const x=e(o,[["render",s]]);export{f as __pageData,x as default};
